!function(){try{var a="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{},n=(new a.Error).stack;n&&(a._sentryDebugIds=a._sentryDebugIds||{},a._sentryDebugIds[n]="6017b936-9eb3-460d-b6b9-3cdfd20c1b94",a._sentryDebugIdIdentifier="sentry-dbid-6017b936-9eb3-460d-b6b9-3cdfd20c1b94")}catch(a){}}();var _global="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{};_global.SENTRY_RELEASE={id:"endfield-returning-user-reward-web@1.0.0"},(self.webpackChunkendfield_returning_user_reward_web=self.webpackChunkendfield_returning_user_reward_web||[]).push([[343],{12343:function(a,n,e){e.r(n),e.d(n,{locale:function(){return r}});var i=e(23068),t=JSON.parse('{"title":"Koneksi Ulang Protokol","description":"Selamat datang kembali di Talos-II, Endministrator.","guide":{"character":"Perlica","lines":"Endmin, bagaimana liburanmu? Banyak hal terjadi di Dijiang dan para operator Divisi Medis terus memintaku mengingatkanmu untuk mendaftar pemeriksaan kesehatan! Semua orang merindukanmu, dan aku ... aku juga menunggumu, Endmin.","button":"Koneksi Ulang Protokol"},"home":{"title":"Koneksi Ulang Protokol","timeCount":"{{DD}} Hari {{HH}} Jam","tabs":{"checkIn":"Sign In Koneksi Ulang","task":"Tugas Koneksi Ulang","survey":"Survei Pemain Kembali"},"checkIn":{"title":"Sign In Koneksi Ulang","intro":"Berpartisipasilah dalam acara [Sign In Koneksi Ulang] selama 7 hari dan dapatkan [Oroberyl] ×2.000 dan berbagai imbalan lainnya!"},"task":{"intro":"Berpartisipasilah dalam acara [Tugas Koneksi Ulang] dan selesaikan berbagai tugas untuk memperoleh <b>[Surat Izin HH Biasa] ×4</b> dan berbagai imbalan lainnya!","taskStatus":{"claimable":"Ambil","ongoing":"Belum Selesai","claimed":"Diambil"},"claimAvailable":"Ambil Semua","currentPoint":"Poin Saat Ini","taskContent":{"daily_login":"Login ke game sebanyak 1 kali per hari (bisa diselesaikan hingga 7 kali)","deploy_factory":"Tempatkan fasilitas Pabrik AIC apa saja","battle_enemy":"Kalahkan 10 musuh apa saja","clear_stage":"Selesaikan Dimensi Protokol mana saja sebanyak 1 kali","manufacture":"Di Dijiang, ambil produk dari kabin produksi mana saja sebanyak 1 kali","upgrade_role_level":"Naikkan level operator mana saja sebanyak 1 kali","collect_ore":"Kumpulkan 1 bijih mineral apa saja","trade_goods":"Berdagang dengan pos depan mana saja sebanyak 1 kali","buy_goods":"Beli barang dari sistem Redistribusi Stok mana saja sebanyak 1 kali","trade_credit":"Beli barang dari Toko Kredit sebanyak 1 kali","collect_item":"Kumpulkan 8 Boletus Pink","ap_cost":"Pakai 1.000 Poin Sanity","boss_challenge":"Selesaikan tantangan Krisis Ulangan mana saja sebanyak 1 kali","world_battle":"Bersihkan Aluvium Energi sebanyak 1 kali (Aluvium Energi Sementara juga akan dihitung)"}},"minimumTimeCount":"<1 JAM","survey":{"surveyStatus":{"not_started":"Belum dimulai","claimed":"Selesai"},"goToButton":"Mulai","unlockText":"Terbuka setelah {{timeCount}}","rewardTip":"Selesaikan survei untuk mendapatkan","surveyContent":{"survey_1":"Survei Hari Pertama Pemain Kembali","survey_2":"Survei Pengalaman Pemain Kembali"},"callbackModal":{"title":"NOTIFIKASI SISTEM","content":"Silakan pergi ke halaman baru untuk mengikuti survei.","button":"Selesai"}}},"rule":{"title":"Detail Event [Koneksi Ulang Protokol]","content":"<b>- Persyaratan Partisipasi -</b>\\n<span>· Level Otoritas Endministrator ≥ 3</span>\\n<span>· Selesaikan misi utama [Bab Ⅰ Proses Ⅰ: Memulai Ulang Lembah]</span>\\n<span>· Tidak login ke game selama ≥ 21 hari berturut-turut</span>\\n<span>· Partisipasi dalam event [Koneksi Ulang Protokol] terakhir ≥ 42 hari yang lalu</span>\\n<span>· Durasi status Kembali Endministrator sama dengan periode event [Koneksi Ulang Protokol]</span>\\n\\n<b>- Aturan Event -</b>\\n<span>· Dengan mengunjungi halaman event [Koneksi Ulang Protokol] untuk pertama kalinya, kamu akan mendapatkan imbalan Koneksi Ulang Protokol, Endministrator.</span>\\n<span>· Selama event, kunjungi halaman [Koneksi Ulang Protokol] dan dapatkan imbalan dengan berpartisipasi dalam [Sign In Koneksi Ulang] dan [Tugas Koneksi Ulang].</span>\\n<span>· Selama event, lakukan sign in di [Sign In Koneksi Ulang] setiap hari untuk mendapatkan imbalan. Sign in harian bisa dilakukan sebanyak 7 kali.</span>\\n<span>· Selama event, selesaikan berbagai [Tugas Koneksi Ulang] untuk mendapatkan poin event dan imbalan. Kumpulkan cukup banyak poin untuk mendapatkan imbalan tambahan.</span>\\n<span>Proses pencatatan data untuk [Tugas Koneksi Ulang] mungkin sedikit terlambat. Setelah menyelesaikan persyaratan tugas, tunggu 2-5 menit untuk menyinkronkan data.</span>\\n<span>· Semua imbalan event akan dikirimkan ke Pesan dalam game. Pesan imbalan akan kedaluwarsa dalam 30 hari, jadi jangan lupa mengambilnya, Endministrator.</span>\\n<span>· Event akan berakhir dalam waktu 14 hari setelah partisipasimu dan ditutup pada pukul 04.00 (waktu server).</span>"},"rewardModal":{"title":"Imbalan Didapatkan","prompt":"Imbalan ini sudah dikirimkan ke Kotak Pesanmu. Jangan lupa mengambilnya, Endmin.","pointTitle":"Dapatkan Poin","closeTip":"Klik untuk menutup","closeTip_PC":"Klik untuk menutup","closeTip_MB":"Ketuk untuk menutup"},"gameItem":{"item_gold":{"name":"T-Cred","usage":"Disingkat TC. Mata uang ini diakui dan digunakan di banyak tempat.","desc":"Mata uang populer yang dilengkapi dengan teknologi antipemalsuan yang sangat canggih. Kalau bisa dipakai untuk beli barang, berarti uangnya bagus."},"item_diamond":{"name":"Oroberyl","usage":"Material buatan yang banyak digunakan untuk merekrut operator.","desc":"Produk khusus dari potongan Origeometri. Batu ini sangat populer karena keindahannya dan kegunaannya yang beragam."},"item_expcard_stage1_high":{"name":"Rekaman Pertarungan Tingkat Lanjut","usage":"Material yang akan memberikan banyak EXP untuk menaikkan level operator Lv.1-60.","desc":"Perangkat penyimpanan yang berisi video rekaman pertarungan. Operator baru bisa memanfaatkannya untuk mendapatkan pengetahuan pertarungan. Dilengkapi juga dengan simulasi berbagai pertarungan bersejarah agar penontonnya bisa memahami kejamnya perang sungguhan yang pernah terjadi di Talos-II."},"item_weapon_expcard_high":{"name":"Set INSP Senjata","usage":"Material yang akan memberikan banyak EXP senjata.","desc":"Perangkat sekali pakai dengan teknologi AIC. Memberikan pemeriksaan otomatis yang menyeluruh pada seluruh struktur senjata. Juga bisa memperbaiki kerusakan material internal dan meningkatkan performa senjata secara signifikan."},"item_char_break_stage_1_2":{"name":"Protodisk","usage":"Material untuk mempromosikan operator ke E1 atau E2.","desc":"Disk khusus yang diproduksi menggunakan Tekno-Protokol dan proses pengukiran data standar. Sering digunakan bersama perangkat lain untuk secara efektif mengurangi kelelahan fisik operator saat latihan."},"item_ticketgacha_standard_single":{"name":"Surat Izin HH Biasa","usage":"Sertifikat internal Endfield Industries. Gunakan item ini untuk melakukan 1 headhunt di [Headhunt Biasa].","desc":"Endfield Industries punya banyak koneksi dan sumber daya di seluruh Talos-II. Setiap kali Divisi SDM Endfield memulai proses headhunt di sektor industri tertentu, selalu ada yang menyambut panggilan itu."},"ap_supply_lt_n":{"name":"Booster Sanity Darurat","usage":"Gunakan item ini untuk memulihkan 40 Sanity. Item ini juga punya tanggal kedaluwarsa.","desc":"Sirop Sanity dosis sedang dalam kemasan khusus untuk situasi darurat. Pengembangnya sepertinya berhasil mendapatkan formula rahasia dari suatu dokumen aneh, yang menggunakan gula dalam jumlah dua kali lipat dalam sediaan khusus ini."},"item_bp_double_reward":{"name":"Izin Penggunaan Sanity","usage":"Gunakan item ini untuk memakai Sanity ganda dan mengambil imbalan ganda pula dari mode game yang memakai Sanity. Satu surat izin harus digunakan untuk setiap 10 Sanity yang terpakai.","desc":"Surat izin yang akan langsung memakai Sanity dalam jumlah besar. Jika Sanity terkuras berlebihan, kesehatan tubuh manusia akan terancam. Sebelum melanjutkan, kamu harus menjalani pemeriksaan medis lengkap dari Divisi Medis."},"item_char_break_stage_3_4":{"name":"Protoset","usage":"Material untuk mempromosikan operator ke E3 atau E4.","desc":"Disk khusus yang diproduksi menggunakan Tekno-Protokol dan proses pengukiran data tingkat lanjut. Sering digunakan bersama perangkat lain untuk mengurangi kelelahan fisik operator selama pelatihan dengan efektif."},"item_expcard_stage2_high":{"name":"Unit Kognitif Tingkat Lanjut","usage":"Material yang akan memberikan banyak EXP untuk menaikkan level operator Lv.61-90.","desc":"Unit penyimpanan data yang dikembangkan oleh Endfield Industries. Unit ini kompatibel dengan berbagai perangkat akses data. Operator baru bisa menggunakannya untuk mempelajari pengetahuan pertarungan dengan efektif. Berkat dukungan yang diberikan oleh Cabal of Tranquility, unit ini juga punya teknologi kompresi data sehingga mampu menampung lebih banyak informasi."},"item_weapon_break_high":{"name":"Cetakan Cor Berat","usage":"Material untuk menyetel senjata.","desc":"Cetakan berat yang dibuat menggunakan material langka. Dengan aktivasi Tekno-Protokol, cetakan ini mampu meningkatkan kekuatan material umum dalam senjata."},"item_char_skill_level_7_12":{"name":"Protohedron","usage":"Material untuk meng-upgrade skill operator.","desc":"Polihedron kristal khusus yang diproduksi menggunakan Tekno-Protokol dan proses kristalisasi canggih. Sering kali dikombinasikan dengan perangkat lain untuk meningkatkan penyerapan fisiologis material penguatan."},"item_case_bp_selfselect_skillsp_1":{"name":"Kerat Pilihan Progresi Tingkat Lanjut Ⅰ","usage":"Dengan membukanya, kamu akan mendapatkan material progresi tingkat lanjut pilihanmu.","desc":"Kerat yang berisi berbagai material serbaguna yang berkualitas tinggi. Performa tempur operator tidak dibatasi ras ataupun pengalaman pertarungan. Kadang, mereka hanya butuh sedikit inspirasi."}},"errMsg":{"code_2000":"Gagal mengirimkan imbalan. Tunggu, lalu coba lagi.","rewardClaimed":"Imbalan ini sudah diambil","code_1002":"Event sedang dimuat, tunggu sebentar, lalu coba masuk lagi ke layar event ini","code_1003":"Event sudah berakhir","networkError":"Kesalahan layanan"},"gamepad":{"hint":{"confirm":"Konfirmasi","close":"Off","closeCurrent":"Tutup layar ini","exit":"Keluar halaman"}}}'),r={lang:i.ELanguage["id-id"],text:t,fonts:{}}}}]);
